const page = $input.first().json.results[0];
const props = page.properties;

const name = props['项目名称']?.title?.[0]?.plain_text || '';
const code = props['项目编号']?.rich_text?.[0]?.plain_text || '';
const client = props['客户名称']?.rich_text?.[0]?.plain_text || '';
const pm = props['PM负责人']?.rich_text?.[0]?.plain_text || '';
const type = props['项目类型']?.select?.name || '数字化交付';
const pageId = page.id;

return [{json: {
  pageId,
  name,
  code,
  client,
  pm,
  type
}}];

